package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() throws Exception {
    String name = "TestItem";
    int quantity = 5;
    long priceInMicros = 123456789; // 123.456789 dollars
    String currencyCode = "USD";

    // Use reflection to create LineItem instance since constructor is not visible
    Class<?> lineItemClass = Class.forName("com.google.gson.examples.android.model.LineItem");
    java.lang.reflect.Constructor<?> constructor = lineItemClass.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    String expected = String.format("(item: %s, qty: %s, price: %.2f %s)",
        name, quantity, priceInMicros / 1000000d, currencyCode);

    // Call toString() via reflection
    String actual = lineItem.toString();

    assertEquals(expected, actual);
  }
}
